var e=[{id:`L5_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`용혈을 버린 기개는 어디로 갔지, 소년?`,JPN:`龍血を捨てた気概はどこに行った、少年？`,ENG:`Where did the determination that you abandoned the Dragon Blood go, boy?`,TWN:`你捨棄龍血的氣勢去哪了，年輕人？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_PRIDE`}}}},{id:`L6_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`도망치는 재주는 통달한 모양이다만, 그것으로 승리를 이룰 수 있겠나?`,JPN:`逃げる芸は極めたようだが、それで勝利できるのか？`,ENG:`I see you are a magnificent escape artist, but surely that won't bring you any victory.`,TWN:`逃跑的本領倒是不錯，不過你覺得光靠那個能贏得了我嗎！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:null,R:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`큭!?`,JPN:`くっ！？`,ENG:`Kgh?!`,TWN:`咳！？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`그리고─`,JPN:`そして─`,ENG:`Oh, and─`,TWN:`還有——`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SEO_YOON_ALT_CA_NULL`,text:{KOREA:`미스틸테인을… 저렇게 가볍게 막는다고?`,JPN:`ミスティルテインを……あんな簡単に止めるですって？`,ENG:`He blocked the Misteltein... without a glimpse.`,TWN:`竟然那麼輕易就擋下……米斯特丁？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`─거기서 기다리고 있어라, 도둑 고양이.`,JPN:`─そこで大人しく待っていろ、泥棒ネコ。`,ENG:`Behave yourself and wait there, stray cat.`,TWN:`——你給我乖乖等著，野貓。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`사람을 할퀴는 그 발톱을 내 몸소 뽑아 줄 테니.`,JPN:`人間を引っ掻くその爪を、直々に抜いてやろう。`,ENG:`I shall rip off those feisty claws myself.`,TWN:`我會親手拔掉你那撓人的爪子。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`SEO_YOON_ALT_CA_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`으앗……?!`,JPN:`うわっ……！？`,ENG:`Woah...!`,TWN:`呃……？！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`괜찮으세요, 미나 양?`,JPN:`大丈夫ですか、ミナさん？`,ENG:`Are you okay, Mina?`,TWN:`你沒事吧，米娜？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`응. 다시 싸워 보니 알겠어.`,JPN:`うん。もう一度戦ってわかった。`,ENG:`Yeah. I'm sure of it now, after fighting him again.`,TWN:`我沒事，只不過再次交手後才發現。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`저 녀석… 레이 선배보다 강해.`,JPN:`あいつ……レイ先輩よりも強い。`,ENG:`That guy... He's more powerful than Ray.`,TWN:`那傢伙……比雷伊前輩更強。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L27_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_CA_NULL`,text:{KOREA:`……그렇죠. 저 자신감도 이해가 안 되는 건 아니에요.`,JPN:`……そうですね。あんなに自信たっぷりなのも理解できなくありません。`,ENG:`...Yes. I understand where his confidence comes from.`,TWN:`……嗯，所以這副自信的模樣也不是不能理解。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_CA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L29_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`싸울 생각도 하지 않던 평민 놈과 나를 비교하느냐?`,JPN:`戦おうとすらしなかった平民と私を比べているのか？`,ENG:`Are you comparing me to the peasant who had absolutely no will to fight?`,TWN:`你竟然把我和那個毫無戰鬥意志的平民相提並論？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`PRINCE_KNIGHT_NULL_NULL`,text:{KOREA:`불쾌하군. 불손한 발언에도 정도가 있는 법이다, 늑대.`,JPN:`不快だな。不遜な発言にも程があるというものだ、狼。`,ENG:`How degrading. There's only so much disrespect I can tolerate, Wolf.`,TWN:`你讓我很不高興，出言不遜也要有個限度，狼。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`PRINCE_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};